import React, { useState } from "react";

function Journey() {

  const [destination, setDestination] = useState("");
  const [time, setTime] = useState("");
  const [message, setMessage] = useState("");

  const startJourney = async () => {

    const res = await fetch("http://localhost:5000/start", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ destination, time })
    })

    const data = await res.json();

    setMessage(data.message)

    setTimeout(() => {

      alert("You did not reach destination on time!")

    }, time * 60000)

  }

  const sendSOS = async () => {

    await fetch("http://localhost:5000/sos", {
      method: "POST"
    })

    alert("Emergency Alert Sent")

  }

  const getLocation = () => {

    navigator.geolocation.getCurrentPosition((pos) => {

      alert(
        "Latitude: " + pos.coords.latitude +
        " Longitude: " + pos.coords.longitude
      )

    })

  }

  return (

    <div className="container">

      <div className="card">

        <h2>Journey Details</h2>

        <input
          type="text"
          placeholder="Destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
        />

        <input
          type="number"
          placeholder="Expected Time (minutes)"
          value={time}
          onChange={(e) => setTime(e.target.value)}
        />

        <button onClick={startJourney}>
          Start Journey
        </button>

        <button onClick={getLocation}>
          Get Location
        </button>

        <button className="sos" onClick={sendSOS}>
          SOS Emergency
        </button>

      </div>

      {message && <p className="result">{message}</p>}

    </div>

  )

}

export default Journey
